using System.ComponentModel;
using System.Net.Http.Json;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerToolType]
public sealed class FetchDataTool
{
    [McpServerTool("fetch_post"), Description("Fetches a post by ID from an external API.")]
    public static async Task<string> FetchPost(
        IHttpClientFactory httpClientFactory,
        [Description("The numeric ID of the post to fetch.")] int id)
    {
        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync($"/posts/{id}");
        response.EnsureSuccessStatusCode();
        var post = await response.Content.ReadFromJsonAsync<Post>();
        return $"Title: {post!.Title}\n\nBody: {post.Body}";
    }

    private sealed record Post(int UserId, int Id, string Title, string Body);
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt("summarize"), Description("Generates a prompt to summarize the given text.")]
    public static IEnumerable<ChatMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Optional desired length: short, medium, or detailed.")] string style = "medium")
    {
        yield return new ChatMessage(
            ChatRole.User,
            $"Please provide a {style} summary of the following text:\n\n{text}");
    }
}

public enum ChatRole { User, Assistant }

public sealed record ChatMessage(ChatRole Role, string Text);

